using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary (default: 3).
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarizer that scores sentences by word-frequency relevance
/// and returns the top-ranked ones in their original document order.
/// </summary>
public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords =
    [
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","of","in","to","for",
        "with","on","at","from","by","about","as","into","through","during",
        "before","after","above","below","between","out","off","over","under",
        "again","further","then","once","it","its","this","that","these",
        "those","i","me","my","we","our","you","your","he","him","his","she",
        "her","they","them","their","what","which","who","whom","how","not",
        "no","nor","so","if","each","every","all","both","few","more","most",
        "other","some","such","only","own","same","than","too","very","just"
    ];

    public (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
            return (string.Join(" ", sentences), sentences.Count, sentences.Count);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scores = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scoring sentences, preserving original order
        var topIndices = scores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i]));
        return (summary, sentences.Count, topIndices.Count);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, double> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (StopWords.Contains(word)) continue;
                freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }

        // Normalize by the maximum frequency
        if (freq.Count > 0)
        {
            var max = freq.Values.Max();
            foreach (var key in freq.Keys)
                freq[key] /= max;
        }

        return freq;
    }

    private static List<double> ScoreSentences(
        List<string> sentences, Dictionary<string, double> wordFrequencies)
    {
        return sentences.Select(sentence =>
            Tokenize(sentence)
                .Where(w => !StopWords.Contains(w) && wordFrequencies.ContainsKey(w))
                .Sum(w => wordFrequencies[w])
        ).ToList();
    }

    private static IEnumerable<string> Tokenize(string sentence) =>
        WordRegex().Matches(sentence).Select(m => m.Value.ToLowerInvariant());

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) =
            summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

